function b(){for(var e=document.querySelectorAll("input[improve-input]"),t=0;t<e.length;t++)e[t].addEventListener("input",function(){var e=this.value;this.hasAttribute("rm-white-spaces")&&(e=e.split(" ").join("")),this.hasAttribute("to-lower")&&(e=e.toLowerCase()),this.hasAttribute("to-upper")&&(e=e.toUpperCase()),this.hasAttribute("to-arabic-numbers")&&(e=e.replace(/:/g,"0").replace(/٠/g,"0").replace(/١/g,"1").replace(/٢/g,"2").replace(/٣/g,"3").replace(/٤/g,"4").replace(/٥/g,"5").replace(/٦/g,"6").replace(/٧/g,"7").replace(/٨/g,"8").replace(/٩/g,"9")),this.hasAttribute("only-numbers")&&(e=e.replace(/\D/g,"")),this.hasAttribute("no-numbers")&&(e=e.replace(/[0-9]/g,"")),this.hasAttribute("only-alphanumeric")&&(e=e.replace(/[^0-9a-z]/gi,"")),this.value=e})}document.addEventListener("DOMContentLoaded",function(){b()},!1);